```c++
            if (ip4Address == AsCoreType(&kWellKnownIpv4OnlyAddress1) ||
                ip4Address == AsCoreType(&kWellKnownIpv4OnlyAddress2))
            {
                // We check that the well-known IPv4 address is
                // present only once in the IPv6 address. In case
                // another instance of it is found for another prefix
                // length, we ignore this address and check other
                // addresses with other well-known IPv4 address.
                // (per RFC 7050 section 3).

                bool foundDuplicate = false;

                for (uint8_t dupLength : kValidNat64PrefixLength)
                {
                    Ip4::Address dupIp4Address;

                    if (dupLength == length)
                    {
                        continue;
                    }

                    dupIp4Address.ExtractFromIp6Address(dupLength, aAddresses[i]));

                    if (dupIp4Address == ip4Address)
                    {
                        foundDuplicate = true;
                        break;
                    }
                }

                if (!foundDuplicate)
                {
                    aAddresses->GetPrefix(length, prefix);
                    break;
                }
            }
